import React from "react";
import { motion } from "framer-motion";
import { useInView } from "react-intersection-observer";

const TimelineItem = ({ item, index }) => {
  const { ref, inView } = useInView({ threshold: 0.3, triggerOnce: true });
  const isLeft = index % 2 === 0;

  return (
    <div ref={ref} className={`flex items-center gap-4 md:gap-8 mb-12 ${isLeft ? "flex-row" : "flex-row-reverse"}`}>
      {/* Content */}
      <motion.div
        className="flex-1"
        initial={{ opacity: 0, x: isLeft ? -60 : 60 }}
        animate={inView ? { opacity: 1, x: 0 } : {}}
        transition={{ duration: 0.8, ease: [0.23, 1, 0.32, 1] }}
      >
        <div className={`glass-card rounded-lg p-6 ${isLeft ? "text-right" : "text-left"}`}>
          <span className="text-gold/60 text-xs tracking-widest uppercase font-body">
            {item.year}
          </span>
          <h4 className="font-serif text-xl gold-text mt-1 mb-2">{item.title}</h4>
          <p className="font-body text-beige/70 text-sm leading-relaxed">{item.description}</p>
        </div>
      </motion.div>

      {/* Center dot */}
      <motion.div
        className="flex-shrink-0 flex flex-col items-center"
        initial={{ opacity: 0, scale: 0 }}
        animate={inView ? { opacity: 1, scale: 1 } : {}}
        transition={{ duration: 0.5, delay: 0.3 }}
      >
        <motion.div
          className="w-12 h-12 rounded-full flex items-center justify-center text-xl z-10"
          style={{ background: "linear-gradient(135deg, #D4AF37, #B8860B)" }}
          animate={inView ? { boxShadow: ["0 0 0px #D4AF37", "0 0 20px #D4AF37", "0 0 0px #D4AF37"] } : {}}
          transition={{ duration: 2, repeat: Infinity }}
        >
          {item.icon}
        </motion.div>
      </motion.div>

      {/* Spacer for opposite side */}
      <div className="flex-1 hidden md:block" />
    </div>
  );
};

const CoupleStory = ({ storyItems }) => {
  const { ref, inView } = useInView({ threshold: 0.1, triggerOnce: true });

  return (
    <section
      ref={ref}
      className="relative py-24 px-4 overflow-hidden"
      style={{ background: "linear-gradient(180deg, #1a0a0a 0%, #0d0000 100%)" }}
    >
      <motion.div
        initial={{ opacity: 0, y: 40 }}
        animate={inView ? { opacity: 1, y: 0 } : {}}
        transition={{ duration: 1 }}
        className="text-center mb-16"
      >
        <span className="ornament">✦ ✦ ✦</span>
        <h2 className="font-serif text-4xl md:text-5xl gold-text mt-4 mb-2">Our Story</h2>
        <p className="font-sans text-beige/50 tracking-widest text-sm uppercase">
          A journey of love
        </p>
      </motion.div>

      <div className="max-w-3xl mx-auto relative">
        {/* Vertical line */}
        <div
          className="absolute left-1/2 top-0 bottom-0 w-px timeline-line hidden md:block"
          style={{ transform: "translateX(-50%)" }}
        />

        {storyItems.map((item, index) => (
          <TimelineItem key={index} item={item} index={index} />
        ))}
      </div>
    </section>
  );
};

export default CoupleStory;
